record.field:
auto = env['base.automation'].search(
    [('name', '=', 'Update Customer Name'), ('active', '=', True)], limit=1)
if auto:
    raise UserError(
        "Delete/archive the 'Update Customer Name' automation first "
        "(Settings > Technical > Automation Rules) - otherwise names re-mangle on save.")

for record in records:
    if not record.name:
        continue
    core = record.name.split(" | ")[0].strip()
    if not core:
        continue
    vals = {}
    if "/" not in core:
        vals['name'] = core
    else:
        parts = [p.strip() for p in core.split("/")]
        vals['name'] = parts[0]
        if len(parts) >= 3:
            vals['street'] = parts[1]
            vals['street2'] = " ".join(parts[2:]).strip()
        else:
            addr = parts[1]
            if "-" in addr:
                s, s2 = addr.split("-", 1)
                vals['street'] = s.strip()
                vals['street2'] = s2.strip()
            else:
                toks = addr.split()
                if toks and any(ch.isdigit() for ch in toks[-1]):
                    vals['street'] = " ".join(toks[:-1]).strip()
                    vals['street2'] = toks[-1].strip()
                else:
                    vals['street'] = addr.strip()
    if not vals.get('name'):
        vals.pop('name', None)
    if vals:
        record.write(vals)
